  {"title": "Đánh giá sức khỏe trước khi tập Yoga", "tag": "Trắc nghiệm", "url": "trac-nghiem/danh-gia-suc-khoe.html", "img": "assets/images/hero.webp", "time": "5 phút", "content": "Bài đánh giá sức khỏe giúp giáo viên hiểu tình trạng của bạn trước khi bắt đầu lớp Yoga khai báo bệnh lý chấn thương mục tiêu sức khỏe."},
  {"title": "Đánh giá sau buổi tập Yoga Trị liệu", "tag": "Trắc nghiệm", "url": "trac-nghiem/danh-gia-sau-buoi-tap.html", "img": "assets/images/hero.webp", "time": "3 phút", "content": "Bài đánh giá sau mỗi buổi tập Yoga Trị liệu giúp theo dõi tiến trình và điều chỉnh bài tập phù hợp mức đau khả năng vận động cảm xúc gửi kết quả cho Mây."},
  {"title": "Đứng cúi người — Uttanasana", "tag": "Tư thế", "url": "tu-the/dung-cui-nguoi.html", "img": "assets/images/poses/uttanasana.webp", "time": "5 phút đọc", "content": "Đứng cúi người Uttanasana Kéo giãn sâu gân khoeo và bắp chân, giải phóng lưng dưới, giảm lo âu và đau đầu, kích thích gan và thận. Đứng thẳng, thở ra gập toàn thân về phía trước từ khớp hông (không từ lưng). Tay chạm sàn hoặc nắm khuỷu tay, đầu thả lỏng. Đau lưng dưới nặng (gập nhẹ hoặc gối cong), thoái hóa đĩa đệm, huyết áp cao."},
  {"title": "Ngồi cúi người — Paschimottanasana", "tag": "Tư thế", "url": "tu-the/ngoi-cui-nguoi.html", "img": "assets/images/poses/paschimottanasana.webp", "time": "5 phút đọc", "content": "Ngồi cúi người Paschimottanasana Kéo giãn toàn bộ mặt sau cơ thể từ gáy đến gót. Kích thích thận, gan, buồng trứng. Giảm căng thẳng, trầm cảm nhẹ. Ngồi trên sàn hai chân duỗi thẳng. Hít vào kéo dài cột sống, thở ra cúi người về phía chân. Tay nắm cạnh bàn chân hoặc ống quyển. Hen suyễn, tiêu chảy, chấn thương lưng dưới — giữ cột sống thẳng hơn với gối đệm."},
  {"title": "Tư thế Trẻ em — Balasana", "tag": "Tư thế", "url": "tu-the/tu-the-tre-em.html", "img": "assets/images/poses/balasana.webp", "time": "5 phút đọc", "content": "Tư thế Trẻ em Balasana Kéo giãn hông, đùi và mắt cá. Thư giãn hệ thần kinh, giảm đau lưng và cổ, làm dịu tâm trí. Quỳ gối, ngồi lùi về gót chân, cúi thân trên ra trước. Trán chạm sàn, hai tay duỗi thẳng trước hoặc để dọc thân. Tiêu chảy, có thai (mở rộng đầu gối hơn), chấn thương đầu gối nặng."},
  {"title": "Nửa gập người — Ardha Uttanasana", "tag": "Tư thế", "url": "tu-the/nua-gap-nguoi.html", "img": "assets/images/poses/ardha-uttanasana.webp", "time": "5 phút đọc", "content": "Nửa gập người Ardha Uttanasana Kéo giãn và giải phóng căng thẳng ở cột sống và gân khoeo. Cải thiện tư thế, chuẩn bị thân nhiệt cho gập sâu. Từ tư thế gập người, nâng nửa thân lên sao cho lưng phẳng song song mặt sàn. Tay chạm hờ cẳng chân hoặc để trên đùi. Chấn thương cổ (đừng ngẩng gập cổ quá sâu), đau thắt lưng (hãy khuỵu nhẹ gối)."},
  {"title": "Ngồi cúi người một chân — Janu Sirsasana", "tag": "Tư thế", "url": "tu-the/ngoi-cui-nguoi-mot-chan.html", "img": "assets/images/poses/janu-sirsasana.webp", "time": "5 phút đọc", "content": "Ngồi cúi người một chân Janu Sirsasana Kéo giãn cột sống, vai và gân khoeo. Kích thích gan và thận. Cải thiện tiêu hóa, giảm lo âu. Ngồi một chân duỗi thẳng, chân kia co lại chân trong đùi đối diện. Hít vào kéo dài lưng, thở ra cúi về phía chân duỗi. Tiêu chảy, chấn thương đầu gối — không gập gối cứng hoàn toàn."},
  {"title": "Dang hai chân cúi — Prasarita Padottanasana", "tag": "Tư thế", "url": "tu-the/dang-hai-chan-cui.html", "img": "assets/images/poses/prasarita-padottanasana.webp", "time": "5 phút đọc", "content": "Dang hai chân cúi Prasarita Padottanasana Kéo giãn đùi trong, bắp chân và cột sống. Làm dịu tinh thần. Tăng cường cơ thân dưới. Đứng hai chân mở rộng 1–1.2m. Tay đặt eo, hít vào, thở ra gập người về trước. Hai tay chống sàn hoặc nắm mắt cá. Huyết áp thấp — đứng dậy từ từ. Chấn thương lưng dưới."},
  {"title": "Tay dưới bàn chân — Padahastasana", "tag": "Tư thế", "url": "tu-the/tay-duoi-ban-chan.html", "img": "assets/images/poses/padahastasana.webp", "time": "5 phút đọc", "content": "Tay dưới bàn chân Padahastasana Kéo giãn sâu gân khoeo, bắp chân và cổ tay. Kích thích gan và thận. Massage nội tạng bụng khi gập sâu. Đứng thẳng, gập người về phía trước. Luồn hai tay dưới lòng bàn chân, ngón tay hướng về gót. Kéo ngực về phía đầu gối. Chấn thương lưng dưới, huyết áp cao, thoát vị đĩa đệm."},
  {"title": "Ngồi dang chân gập — Upavistha Konasana", "tag": "Tư thế", "url": "tu-the/ngoi-dang-chan-gap.html", "img": "assets/images/poses/upavista-konasana.webp", "time": "5 phút đọc", "content": "Ngồi dang chân gập Upavistha Konasana Kéo giãn sâu đùi trong, gân khoeo và bẹn. Kích thích nội tạng bụng. Làm dịu hệ thần kinh. Ngồi hai chân mở rộng sang hai bên. Hít vào kéo dài cột sống, thở ra gập người về trước, tay với ra phía trước trên sàn. Chấn thương lưng dưới — giữ cột sống thẳng, không ép gập quá sâu."},
  {"title": "Tư thế Kim tự tháp — Parsvottanasana", "tag": "Tư thế", "url": "tu-the/tu-the-kim-tu-thap.html", "img": "assets/images/poses/parsvottanasana.webp", "time": "5 phút đọc", "content": "Tư thế Kim tự tháp Parsvottanasana Kéo giãn cột sống, vai, cổ tay và gân khoeo. Cải thiện tư thế và thăng bằng. Kích thích tiêu hóa. Đứng một chân trước, một chân sau (cách ~1m). Tay chắp sau lưng (reverse prayer). Gập thân trên về phía chân trước. Huyết áp cao, chấn thương gân khoeo hoặc lưng dưới."},
  {"title": "Tư thế Rùa — Kurmasana", "tag": "Tư thế", "url": "tu-the/tu-the-rua.html", "img": "assets/images/poses/kurmasana.webp", "time": "5 phút đọc", "content": "Tư thế Rùa Kurmasana Kéo giãn rất sâu cột sống, vai và gân khoeo. Kích thích tim và phổi. Thư giãn hệ thần kinh, giảm đau đầu. Ngồi hai chân mở rộng, gối hơi cong. Gập người về trước, luồn hai tay dưới đầu gối ra hai bên. Ngực hạ dần xuống sàn. Chấn thương cột sống, vai hoặc hông. Thoát vị đĩa đệm. Thai kỳ."},
  {"title": "Tư thế Rắn hổ mang — Bhujangasana", "tag": "Tư thế", "url": "tu-the/tu-the-ran-ho-mang.html", "img": "assets/images/poses/bhujangasana.webp", "time": "5 phút đọc", "content": "Tư thế Rắn hổ mang Bhujangasana Tăng cường cơ lưng, mở ngực và phổi, kích thích nội tạng bụng, thư giãn lưng dưới, nâng cao tâm trạng. Nằm sấp, tay đặt dưới vai. Hít vào nâng ngực và đầu lên. Khuỷu tay hơi cong, vai kéo xuống và ra sau. Hội chứng ống cổ tay, chấn thương lưng, thai kỳ."},
  {"title": "Tư thế Cầu — Setu Bandha Sarvangasana", "tag": "Tư thế", "url": "tu-the/tu-the-cau.html", "img": "assets/images/poses/setu-bandhasana.webp", "time": "5 phút đọc", "content": "Tư thế Cầu Setu Bandha Sarvangasana Mở ngực, cổ và cột sống. Tăng cường cơ đùi sau và cơ mông. Kích thích tuyến giáp, giảm lo âu. Nằm ngửa, gập gối đặt lòng bàn chân sàn gần mông. Hít vào nâng hông lên, hai tay đặt dưới lưng hoặc song song thân. Chấn thương cổ — giữ cổ không xoay khi trong tư thế."},
  {"title": "Tư thế Lạc đà — Ustrasana", "tag": "Tư thế", "url": "tu-the/tu-the-lac-da.html", "img": "assets/images/poses/ustrasana.webp", "time": "5 phút đọc", "content": "Tư thế Lạc đà Ustrasana Kéo giãn toàn bộ mặt trước cơ thể, cột sống và cổ họng. Tăng cường cơ lưng. Mở tim, tăng năng lượng. Quỳ gối, hông rộng bằng vai. Tay đặt lưng dưới hoặc nắm gót chân. Nâng ngực lên, đầu thả nhẹ ra sau. Huyết áp thấp hoặc cao, đau đầu, mất ngủ, chấn thương lưng dưới hoặc cổ."},
  {"title": "Tư thế Châu chấu — Salabhasana", "tag": "Tư thế", "url": "tu-the/tu-the-chau-chau.html", "img": "assets/images/poses/salabhasana.webp", "time": "5 phút đọc", "content": "Tư thế Châu chấu Salabhasana Tăng cường cơ lưng toàn bộ, cơ mông và cơ chân. Kích thích nội tạng bụng. Giảm đau lưng mãn tính. Nằm sấp, hai tay xuôi thân hoặc dưới bụng. Hít vào nâng chân (hoặc cả thân trên) lên khỏi sàn, giữ chân thẳng. Thai kỳ, chấn thương lưng nặng, đau đầu."},
  {"title": "Tư thế Cánh cung — Dhanurasana", "tag": "Tư thế", "url": "tu-the/tu-the-canh-cung.html", "img": "assets/images/poses/dhanurasana.webp", "time": "5 phút đọc", "content": "Tư thế Cánh cung Dhanurasana Kéo giãn toàn bộ mặt trước cơ thể. Tăng cường cơ lưng. Kích thích cơ quan sinh sản và tuyến thượng thận. Nằm sấp, gập gối. Tay với ra sau nắm mắt cá chân. Hít vào nâng ngực và chân lên cùng lúc, cơ thể như hình cánh cung. Huyết áp cao hoặc thấp, đau nửa đầu, mất ngủ, thai kỳ."},
  {"title": "Tư thế Cá — Matsyasana", "tag": "Tư thế", "url": "tu-the/tu-the-ca.html", "img": "assets/images/poses/matsyasana.webp", "time": "5 phút đọc", "content": "Tư thế Cá Matsyasana Mở ngực và cổ họng, kéo giãn cơ gian sườn. Kích thích tuyến giáp và cận giáp. Giảm căng thẳng cổ vai. Nằm ngửa, tay đặt dưới mông. Hít vào nâng ngực lên, đầu thả nhẹ ra sau chạm sàn nhẹ nhàng. Huyết áp cao hoặc thấp, đau nửa đầu, mất ngủ, chấn thương cổ."},
  {"title": "Chó ngửa mặt — Urdhva Mukha Svanasana", "tag": "Tư thế", "url": "tu-the/cho-ngua-mat.html", "img": "assets/images/poses/urdhva-mukha-svanasana.webp", "time": "5 phút đọc", "content": "Chó ngửa mặt Urdhva Mukha Svanasana Mở rộng ngực và phổi. Tăng cường cánh tay, cổ tay và cột sống. Kích thích nội tạng bụng. Giảm trầm cảm nhẹ. Nằm sấp, hai tay đặt cạnh ngực. Hít vào ấn tay nâng toàn thân lên, hông và đùi rời khỏi sàn. Mu bàn chân ấn sàn. Hội chứng ống cổ tay, đau đầu, thai kỳ, chấn thương lưng."},
  {"title": "Tư thế Bánh xe — Urdhva Dhanurasana", "tag": "Tư thế", "url": "tu-the/tu-the-banh-xe.html", "img": "assets/images/poses/urdhva-dhanurasana.webp", "time": "5 phút đọc", "content": "Tư thế Bánh xe Urdhva Dhanurasana Kéo giãn toàn bộ mặt trước cơ thể. Tăng cường cánh tay, chân, bụng và cột sống. Kích thích tuyến giáp và yên. Nằm ngửa, gập gối đặt bàn chân sàn. Tay đặt cạnh đầu, ngón hướng vai. Hít vào đẩy toàn thân lên thành hình cầu vồng. Đau đầu, tiêu chảy, huyết áp cao hoặc thấp, chấn thương cổ tay hoặc lưng."},
  {"title": "Tư thế Trăng lưỡi liềm — Anjaneyasana", "tag": "Tư thế", "url": "tu-the/tu-the-trang-luoi-liem.html", "img": "assets/images/poses/anjaneyasana.webp", "time": "5 phút đọc", "content": "Tư thế Trăng lưỡi liềm Anjaneyasana Kéo giãn sâu cơ gấp hông, đùi trước và bẹn. Mở ngực và vai. Tăng năng lượng và sự tự tin. Từ Lunge, hạ gối sau xuống sàn. Gối trước gập 90°. Hai tay vươn lên trời, nhẹ nhàng uốn lưng. Chấn thương đầu gối — kê đệm dưới gối sau. Huyết áp cao — không giơ tay quá cao."},
  {"title": "Anh hùng nằm ngửa — Supta Virasana", "tag": "Tư thế", "url": "tu-the/anh-hung-nam-ngua.html", "img": "assets/images/poses/supta-virasana.webp", "time": "5 phút đọc", "content": "Anh hùng nằm ngửa Supta Virasana Kéo giãn sâu đùi trước, mắt cá và bụng. Cải thiện tiêu hóa. Giảm mệt mỏi chân sau đứng lâu. Từ Virasana, từ từ nằm ngửa ra sau, dùng khuỷu tay đỡ. Tay đặt xuôi thân hoặc vươn qua đầu. Chấn thương đầu gối hoặc mắt cá — ngồi trên gối đệm, không ép nằm hoàn toàn."},
  {"title": "Tư thế Tam giác — Trikonasana", "tag": "Tư thế", "url": "tu-the/tu-the-tam-giac.html", "img": "assets/images/poses/trikonasana.webp", "time": "5 phút đọc", "content": "Tư thế Tam giác Trikonasana Kéo giãn sâu hông, bẹn, gân khoeo và sườn. Mở rộng ngực và vai. Tăng cường cơ chân, giảm stress. Hai chân mở rộng, bàn chân trước quay 90°. Tay trước hạ xuống chạm ống chân hoặc sàn, tay sau vươn thẳng lên trời. Tiêu chảy, đau đầu, huyết áp thấp, chấn thương cổ — mắt nhìn thẳng."},
  {"title": "Tư thế Bán nguyệt — Ardha Chandrasana", "tag": "Tư thế", "url": "tu-the/tu-the-ban-nguyet.html", "img": "assets/images/poses/ardha-chandrasana.webp", "time": "5 phút đọc", "content": "Tư thế Bán nguyệt Ardha Chandrasana Kéo giãn sườn, cột sống và đùi trong. Tăng cường thăng bằng. Mở hông và ngực sang bên. Từ Tam giác, chuyển trọng lượng lên chân trước, nâng chân sau song song sàn. Tay trên vươn lên trời, thân mở sang bên. Đau đầu, huyết áp thấp, tiêu chảy, mất ngủ."},
  {"title": "Tư thế Góc mở rộng — Utthita Parsvakonasana", "tag": "Tư thế", "url": "tu-the/tu-the-goc-mo-rong.html", "img": "assets/images/poses/utthita-parsvakonasana.webp", "time": "5 phút đọc", "content": "Tư thế Góc mở rộng Utthita Parsvakonasana Kéo giãn sườn, bẹn và đùi trong. Tăng cường chân và cột sống. Kích thích tiêu hóa. Từ Chiến binh II, tay trước tựa khuỷu lên đùi hoặc sàn. Tay sau vươn qua đầu tạo đường thẳng từ bàn chân đến ngón tay. Đau đầu, huyết áp thấp hoặc cao."},
  {"title": "Nghiêng sườn đứng — Nitambhasana", "tag": "Tư thế", "url": "tu-the/nghieng-suon-dung.html", "img": "assets/images/poses/nitambhasana.webp", "time": "5 phút đọc", "content": "Nghiêng sườn đứng Nitambhasana Kéo giãn cơ gian sườn và cạnh thân, giải phóng căng thẳng lưng bên, mở rộng dung tích phổi. Đứng thẳng, một tay lên trên đầu, nghiêng người sang bên đối diện. Hông không được lệch ra ngoài. Huyết áp thấp, chóng mặt."},
  {"title": "Cổng vòm — Parighasana", "tag": "Tư thế", "url": "tu-the/cong-vom.html", "img": "assets/images/poses/parighasana.webp", "time": "5 phút đọc", "content": "Cổng vòm Parighasana Kéo giãn sâu cạnh thân, cơ gian sườn và hông. Tăng linh hoạt cột sống sang hai bên. Quỳ một gối, duỗi chân còn lại sang bên. Một tay đặt lên chân duỗi, tay kia vươn qua đầu theo hướng chân duỗi. Chấn thương đầu gối — dùng tấm đỡ dưới gối."},
  {"title": "Nghiêng lườn ngồi — Parivrtta Janu Sirsasana", "tag": "Tư thế", "url": "tu-the/nghieng-luon-ngoi.html", "img": "assets/images/poses/parivrtta-janu-sirsasana.webp", "time": "5 phút đọc", "content": "Nghiêng lườn ngồi Parivrtta Janu Sirsasana Kéo giãn sâu cạnh thân, vai và gân khoeo. Kích thích gan và thận. Cải thiện tiêu hóa. Ngồi một chân duỗi, chân kia co. Nghiêng thân về phía chân duỗi, tay trên vươn qua đầu nắm bàn chân. Mở ngực lên trần. Tiêu chảy, chấn thương đầu gối hoặc lưng dưới."},
  {"title": "Tư thế Vishnu nằm — Anantasana", "tag": "Tư thế", "url": "tu-the/tu-the-vishnu-nam.html", "img": "assets/images/poses/anantasana.webp", "time": "5 phút đọc", "content": "Tư thế Vishnu nằm Anantasana Kéo giãn đùi trong và gân khoeo. Tăng cường cơ bụng bên. Cải thiện thăng bằng khi nằm nghiêng. Nằm nghiêng, đầu tựa lên tay dưới. Nâng chân trên lên thẳng, tay trên nắm ngón chân cái. Giữ thăng bằng. Chấn thương cổ, vai hoặc gân khoeo."},
  {"title": "Nghiêng lườn ngồi thiền — Parsva Sukhasana", "tag": "Tư thế", "url": "tu-the/nghieng-luon-ngoi-thien.html", "img": "assets/images/poses/parsva-sukhasana.webp", "time": "5 phút đọc", "content": "Nghiêng lườn ngồi thiền Parsva Sukhasana Kéo giãn nhẹ cơ gian sườn và vai. Mở rộng lồng ngực. Dễ tiếp cận cho người mới bắt đầu. Ngồi xếp bằng, một tay chống sàn bên cạnh. Tay kia vươn lên và cong qua đầu, nghiêng nhẹ sang bên tay chống. Chấn thương vai — giảm biên độ."},
  {"title": "Chiến binh đảo ngược — Viparita Virabhadrasana", "tag": "Tư thế", "url": "tu-the/chien-binh-dao-nguoc.html", "img": "assets/images/poses/viparita-virabhadrasana.webp", "time": "5 phút đọc", "content": "Chiến binh đảo ngược Viparita Virabhadrasana Kéo giãn sâu cạnh thân và vai. Mở ngực. Tăng cường chân. Kết hợp sức mạnh và linh hoạt. Từ Chiến binh II, giữ gối trước cong. Nghiêng thân về phía sau, tay trước vươn lên trời, tay sau trượt xuống chân sau. Chấn thương vai, cổ hoặc đầu gối."},
  {"title": "Nghiêng lườn đứng — Ardha Kati Chakrasana", "tag": "Tư thế", "url": "tu-the/nghieng-luon-dung.html", "img": "assets/images/poses/ardha-kati-chakrasana.webp", "time": "5 phút đọc", "content": "Nghiêng lườn đứng Ardha Kati Chakrasana Kéo giãn cơ gian sườn, cải thiện tư thế. Tăng linh hoạt cột sống bên. Phù hợp khởi động. Đứng thẳng hai chân chụm. Một tay giữ eo, tay kia vươn lên trời. Nghiêng thân sang bên tay giữ eo, hông giữ thẳng. Huyết áp thấp, chóng mặt."},
  {"title": "Vặn xoắn ngồi — Ardha Matsyendrasana", "tag": "Tư thế", "url": "tu-the/van-xoan-ngoi.html", "img": "assets/images/poses/ardha-matsyendrasana.webp", "time": "5 phút đọc", "content": "Vặn xoắn ngồi Ardha Matsyendrasana Tăng linh hoạt cột sống, massage thận và gan, kích thích tiêu hóa, giảm mệt mỏi và đau lưng. Ngồi, gập một chân, đặt bàn chân qua chân kia. Tay đối diện tựa khuỷu vào đầu gối. Xoắn thân từ đáy cột sống. Thai kỳ, chấn thương cột sống, thoát vị đĩa đệm — chỉ xoắn nhẹ."},
  {"title": "Tam giác xoay — Parivrtta Trikonasana", "tag": "Tư thế", "url": "tu-the/tam-giac-xoay.html", "img": "assets/images/poses/parivrtta-trikonasana.webp", "time": "5 phút đọc", "content": "Tam giác xoay Parivrtta Trikonasana Tăng cường cơ bụng và lưng, kích thích tiêu hóa, cải thiện thăng bằng và sự tập trung. Từ tư thế đứng, tay đối diện chạm sàn cạnh chân trước, tay sau vươn lên. Giữ hông song song sàn. Huyết áp thấp, đau nửa đầu, tiêu chảy, mất ngủ."},
  {"title": "Chiến binh xoay — Parivrtta Parsvakonasana", "tag": "Tư thế", "url": "tu-the/chien-binh-xoay.html", "img": "assets/images/poses/parivrtta-parsvakonasana.webp", "time": "5 phút đọc", "content": "Chiến binh xoay Parivrtta Parsvakonasana Tăng cường chân và cột sống, kích thích tiêu hóa, cải thiện thăng bằng. Kéo giãn sâu lưng và hông. Từ Lunge thấp, xoay thân, khuỷu tay đối diện tựa đầu gối. Tay trên vươn qua đầu tạo đường dài. Huyết áp thấp hoặc cao, đau đầu, mất ngủ."},
  {"title": "Xoắn nằm ngửa — Supta Matsyendrasana", "tag": "Tư thế", "url": "tu-the/xoan-nam-ngua.html", "img": "assets/images/poses/supta-matsyendrasana.webp", "time": "5 phút đọc", "content": "Xoắn nằm ngửa Supta Matsyendrasana Massage nhẹ nội tạng bụng, giải phóng căng cột sống và hông, kéo giãn vai và cổ. Thư giãn sâu. Nằm ngửa, kéo một đầu gối qua bên đối diện. Tay cùng bên giang thẳng, đầu quay nhẹ hướng tay đó. Đau lưng dưới — giảm biên độ xoắn."},
  {"title": "Xoắn ngồi đơn giản — Bharadvajasana", "tag": "Tư thế", "url": "tu-the/xoan-ngoi-don-gian.html", "img": "assets/images/poses/bharadvajasana.webp", "time": "5 phút đọc", "content": "Xoắn ngồi đơn giản Bharadvajasana Dịu nhẹ cho cột sống, vai và cổ. Kích thích nội tạng bụng. Phù hợp người đau lưng nhẹ. Ngồi, hai chân để một bên phải (hoặc trái). Xoay thân về phía trái, tay phải đặt lên đầu gối trái, tay trái ra sau tựa sàn. Tiêu chảy, nhức đầu, huyết áp thấp hoặc cao."},
  {"title": "Xoắn tứ chi — Parivrtta Balasana", "tag": "Tư thế", "url": "tu-the/xoan-tu-chi.html", "img": "assets/images/poses/parivrtta-balasana.webp", "time": "5 phút đọc", "content": "Xoắn tứ chi Parivrtta Balasana Giải phóng căng thẳng lưng trên và vai, xoắn nhẹ cột sống ngực, thích hợp khởi động. Từ Tứ chi (bò), luồn một tay qua sàn sang bên đối diện. Vai và má chạm sàn. Tay trên có thể vươn lên trời. Chấn thương vai hoặc cổ tay."},
  {"title": "Lunge xoắn — Parivrtta Anjaneyasana", "tag": "Tư thế", "url": "tu-the/lunge-xoan.html", "img": "assets/images/poses/parivrtta-anjaneyasana.webp", "time": "5 phút đọc", "content": "Lunge xoắn Parivrtta Anjaneyasana Kéo giãn cơ gấp hông và đùi trước. Xoắn sâu cột sống, kích thích tiêu hóa. Tăng cường thăng bằng và sức mạnh chân. Từ Lunge thấp, chắp tay trước ngực. Xoắn thân sang bên, khuỷu tay đối diện móc vào ngoài đầu gối trước. Nhìn lên trần. Chấn thương đầu gối, lưng dưới hoặc cổ. Huyết áp thấp."},
  {"title": "Ghế xoay — Parivrtta Utkatasana", "tag": "Tư thế", "url": "tu-the/ghe-xoay.html", "img": "assets/images/poses/parivrtta-utkatasana.webp", "time": "5 phút đọc", "content": "Ghế xoay Parivrtta Utkatasana Tăng cường chân, cốt lõi và cột sống. Kích thích tiêu hóa. Giải độc nhẹ nhàng qua massage nội tạng. Từ Utkatasana (ghế), chắp tay trước ngực. Xoay thân sang một bên, khuỷu tay đặt ngoài đầu gối đối diện. Huyết áp thấp, đau đầu, mất ngủ, chấn thương đầu gối."},
  {"title": "Cân bằng tay xoắn — Eka Pada Koundinyasana II", "tag": "Tư thế", "url": "tu-the/can-bang-tay-xoan.html", "img": "assets/images/poses/eka-pada-koundinyasana.webp", "time": "5 phút đọc", "content": "Cân bằng tay xoắn Eka Pada Koundinyasana II Tăng cường cổ tay, cánh tay và cốt lõi. Kết hợp xoắn sâu với cân bằng tay. Phát triển sức mạnh và sự tự tin. Từ tư thế Chaturanga, xoắn thân đặt một đùi lên cánh tay. Duỗi chân đó sang bên, chân kia duỗi thẳng ra sau. Nâng toàn thân khỏi sàn. Hội chứng ống cổ tay, chấn thương vai hoặc cổ tay, thai kỳ."},
  {"title": "Xoắn cột sống đứng — Katichakrasana", "tag": "Tư thế", "url": "tu-the/xoan-cot-song-dung.html", "img": "assets/images/poses/katichakrasana.webp", "time": "5 phút đọc", "content": "Xoắn cột sống đứng Katichakrasana Làm linh hoạt cột sống, giảm cứng lưng. Kích thích tiêu hóa. Phù hợp khởi động trước buổi tập. Đứng hai chân rộng bằng vai. Xoay thân sang bên, tay đối diện đặt lên vai, tay cùng bên quấn ra sau lưng. Đổi bên. Thoát vị đĩa đệm, đau lưng cấp tính."},
  {"title": "Tư thế Thuyền — Navasana", "tag": "Tư thế", "url": "tu-the/tu-the-thuyen.html", "img": "assets/images/poses/navasana.webp", "time": "5 phút đọc", "content": "Tư thế Thuyền Navasana Tăng cường mạnh cơ bụng sâu (transversus abdominis), cơ gấp hông và cột sống. Cải thiện tiêu hóa. Ngồi, nâng hai chân lên 45°, hai tay duỗi về phía trước song song sàn. Thân và chân tạo hình chữ V, lưng thẳng. Hen suyễn, tiêu chảy, đau đầu, tim yếu, mất ngủ, huyết áp thấp, thai kỳ."},
  {"title": "Tư thế Tấm ván — Phalakasana", "tag": "Tư thế", "url": "tu-the/tu-the-tam-van.html", "img": "assets/images/poses/phalakasana.webp", "time": "5 phút đọc", "content": "Tư thế Tấm ván Phalakasana Tăng cường toàn bộ cốt lõi, vai và cánh tay. Cải thiện tư thế, tăng sức bền. Chống hai tay xuống sàn (hoặc khuỷu tay), hai chân duỗi thẳng ra sau. Cơ thể thẳng như tấm ván từ đầu đến gót. Hội chứng ống cổ tay, đau vai cấp tính."},
  {"title": "Tấm ván bên — Vasisthasana", "tag": "Tư thế", "url": "tu-the/tam-van-ben.html", "img": "assets/images/poses/vasisthasana.webp", "time": "5 phút đọc", "content": "Tấm ván bên Vasisthasana Tăng cường cơ bụng bên (obliques), cổ tay và vai. Cải thiện thăng bằng và sự tập trung. Từ Tấm ván, xoay người sang bên, một tay chống sàn, tay kia vươn lên trời. Cơ thể thẳng hàng. Hội chứng ống cổ tay, chấn thương vai hoặc mắt cá."},
  {"title": "Hạ lưng từng bên — Jathara Parivartanasana", "tag": "Tư thế", "url": "tu-the/ha-lung-tung-ben.html", "img": "assets/images/poses/jathara-parivartanasana.webp", "time": "5 phút đọc", "content": "Hạ lưng từng bên Jathara Parivartanasana Tăng cường cơ bụng chéo và cơ thắt lưng, massage nhẹ cột sống, giảm đau lưng dưới. Nằm ngửa, nâng hai chân thẳng lên trên. Từ từ hạ chân sang phải (không chạm sàn), giữ, rồi đổi bên. Chấn thương cột sống lưng cấp tính."},
  {"title": "Tấm ván ngửa — Purvottanasana", "tag": "Tư thế", "url": "tu-the/tam-van-ngua.html", "img": "assets/images/poses/purvottanasana.webp", "time": "5 phút đọc", "content": "Tấm ván ngửa Purvottanasana Nâng cao sức mạnh cốt lõi, cơ lưng, cánh tay và cổ tay. Kéo giãn chuyên sâu mặt trước cơ thể (ngực, vai, đùi). Ngồi thẳng chân. Đặt hai tay phía sau hông. Hít vào, ấn gót và tay xuống sàn, nâng hông lên cao thành một đường thẳng. Chấn thương cổ tay, chấn thương cổ (giữ đầu thẳng thay vì thả ngửa)."},
  {"title": "Chống đẩy thấp — Chaturanga Dandasana", "tag": "Tư thế", "url": "tu-the/chong-day-thap.html", "img": "assets/images/poses/chaturanga-dandasana-v2.webp", "time": "5 phút đọc", "content": "Chống đẩy thấp Chaturanga Dandasana Tăng cường toàn bộ cốt lõi, tay, vai và cổ tay. Xây dựng sức bền. Chuẩn bị cho tư thế cân bằng tay. Từ Tấm ván, hạ thân xuống giữ cách sàn vài cm. Khuỷu tay cong 90° sát sườn. Giữ cơ thể thẳng. Hội chứng ống cổ tay, chấn thương vai, thai kỳ."},
  {"title": "Tư thế Ghế — Utkatasana", "tag": "Tư thế", "url": "tu-the/tu-the-ghe.html", "img": "assets/images/poses/utkatasana-v2.webp", "time": "5 phút đọc", "content": "Tư thế Ghế Utkatasana Tăng cường đùi, mông, bắp chân và cốt lõi. Kéo giãn vai và ngực. Kích thích tim và cơ hoành. Đứng thẳng, gập gối như ngồi ghế vô hình. Đùi gần song song sàn. Hai tay vươn thẳng lên trời. Huyết áp thấp, đau đầu, mất ngủ, chấn thương đầu gối."},
  {"title": "Tư thế Quạ — Bakasana", "tag": "Tư thế", "url": "tu-the/tu-the-qua.html", "img": "assets/images/poses/bakasana-v2.webp", "time": "5 phút đọc", "content": "Tư thế Quạ Bakasana Tăng cường mạnh cổ tay, cánh tay và cốt lõi. Cải thiện thăng bằng và tập trung. Xây dựng sự tự tin. Ngồi xổm, hai tay chống sàn rộng bằng vai. Gối tựa lên mặt sau cánh tay. Nghiêng về trước, nâng chân khỏi sàn. Hội chứng ống cổ tay, thai kỳ, chấn thương vai."},
  {"title": "Tư thế Cân — Tolasana", "tag": "Tư thế", "url": "tu-the/tu-the-can.html", "img": "assets/images/poses/tolasana.webp", "time": "5 phút đọc", "content": "Tư thế Cân Tolasana Tăng cường cánh tay, vai và cốt lõi. Cải thiện sức mạnh nắm tay. Phát triển kiểm soát cơ thể. Ngồi xếp bằng (hoặc Padmasana), hai tay đặt sàn cạnh hông. Ấn mạnh tay, nâng toàn thân rời sàn. Giữ 5–10 giây. Chấn thương cổ tay, vai hoặc đầu gối. Hông cứng."},
  {"title": "Nửa thuyền — Ardha Navasana", "tag": "Tư thế", "url": "tu-the/nua-thuyen.html", "img": "assets/images/poses/ardha-navasana.webp", "time": "5 phút đọc", "content": "Nửa thuyền Ardha Navasana Tăng cường cơ bụng dưới và cơ gấp hông. Dễ tiếp cận hơn Navasana đầy đủ. Xây dựng nền tảng cốt lõi. Ngồi, gập gối, nâng chân lên ống quyển song song sàn. Tay duỗi về phía trước ngang đầu gối. Lưng thẳng. Đau lưng dưới cấp tính, thai kỳ."},
  {"title": "Tư thế Bướm — Baddha Konasana", "tag": "Tư thế", "url": "tu-the/tu-the-buom.html", "img": "assets/images/poses/baddha-konasana.webp", "time": "5 phút đọc", "content": "Tư thế Bướm Baddha Konasana Kéo giãn hông, bẹn và đùi trong. Kích thích tim và tuần hoàn. Giảm mệt mỏi và lo âu. Ngồi, hai lòng bàn chân áp vào nhau, gối mở sang hai bên tự nhiên. Cầm bàn chân, cột sống thẳng và thở sâu. Chấn thương bẹn hoặc đầu gối — kê gối đệm dưới đùi."},
  {"title": "Tư thế Hoa Sen — Padmasana", "tag": "Tư thế", "url": "tu-the/tu-the-hoa-sen.html", "img": "assets/images/poses/padmasana.webp", "time": "5 phút đọc", "content": "Tư thế Hoa Sen Padmasana Mở sâu hông và khớp háng, thiết lập nền tảng vững chắc cho thiền định. Kéo giãn mắt cá và đầu gối. Ngồi, đặt lần lượt từng bàn chân lên đùi đối diện, mặt bàn chân hướng lên. Cột sống thẳng, tay đặt mudra. Chấn thương mắt cá hoặc đầu gối — không ép khi hông chưa đủ mở."},
  {"title": "Tư thế Bồ câu — Eka Pada Rajakapotasana", "tag": "Tư thế", "url": "tu-the/tu-the-bo-cau.html", "img": "assets/images/poses/eka-pada-rajakapotasana.webp", "time": "5 phút đọc", "content": "Tư thế Bồ câu Eka Pada Rajakapotasana Mở sâu hông ngoài và bẹn. Kéo giãn cơ mông và cơ piriformis. Giảm đau thần kinh tọa. Từ Chó úp mặt, đưa chân trái ra trước gập gối để trước thân. Chân phải duỗi thẳng ra sau. Cột sống thẳng hoặc cúi người. Chấn thương đầu gối, mắt cá hoặc hông — điều chỉnh biên độ."},
  {"title": "Tư thế Anh hùng — Virasana", "tag": "Tư thế", "url": "tu-the/tu-the-anh-hung.html", "img": "assets/images/poses/virasana.webp", "time": "5 phút đọc", "content": "Tư thế Anh hùng Virasana Kéo giãn đùi trước, đầu gối và mắt cá. Cải thiện tiêu hóa. Giảm mệt mỏi chân và phù sau đứng lâu. Quỳ gối, hai chân mở hơn hông. Ngồi chậm xuống giữa hai gót chân. Cột sống thẳng, tay đặt đùi. Chấn thương đầu gối hoặc mắt cá — ngồi trên gối đệm giữa hai chân."},
  {"title": "Tư thế Ngồi xổm — Malasana", "tag": "Tư thế", "url": "tu-the/tu-the-ngoi-xom.html", "img": "assets/images/poses/malasana.webp", "time": "5 phút đọc", "content": "Tư thế Ngồi xổm Malasana Mở rộng hông, háng và lưng dưới. Kích thích tiêu hóa. Tăng linh hoạt mắt cá chân. Ngồi xổm hai chân rộng bằng vai. Khuỷu tay chống vào mặt trong đầu gối, tay chắp lại trước ngực, lưng thẳng. Chấn thương đầu gối, lưng dưới — kê gối dưới gót."},
  {"title": "Em bé vui vẻ — Ananda Balasana", "tag": "Tư thế", "url": "tu-the/em-be-vui-ve.html", "img": "assets/images/poses/ananda-balasana.webp", "time": "5 phút đọc", "content": "Em bé vui vẻ Ananda Balasana Giải phóng hông và lưng dưới, kéo giãn nội hông và bẹn. Nhẹ nhàng massage cột sống. Thư giãn sâu. Nằm ngửa, gập gối lên ngực. Tay nắm cạnh ngoài bàn chân, kéo gối về phía nách. Lưng luôn áp sàn. Thai kỳ, chấn thương đầu gối hoặc hông nặng."},
  {"title": "Tư thế Mặt bò — Gomukhasana", "tag": "Tư thế", "url": "tu-the/tu-the-mat-bo.html", "img": "assets/images/poses/gomukhasana.webp", "time": "5 phút đọc", "content": "Tư thế Mặt bò Gomukhasana Mở sâu vai, hông và ngực. Kéo giãn cơ tam đầu, cơ lưng và mắt cá. Giảm căng thẳng và lo âu. Ngồi, xếp đầu gối chồng lên nhau. Tay trên vươn qua đầu và gập khuỷu, tay dưới luồn sau lưng lên. Nắm tay phía sau. Chấn thương vai, đầu gối hoặc hông — dùng dây đai nếu tay không nắm được."},
  {"title": "Nằm nắm ngón chân — Supta Padangusthasana", "tag": "Tư thế", "url": "tu-the/nam-nam-ngon-chan.html", "img": "assets/images/poses/supta-padangusthasana.webp", "time": "5 phút đọc", "content": "Nằm nắm ngón chân Supta Padangusthasana Kéo giãn gân khoeo và bắp chân an toàn khi nằm. Giảm đau lưng dưới. Cải thiện linh hoạt chân. Nằm ngửa, nâng một chân lên thẳng. Tay nắm ngón chân cái (hoặc dùng dây đai). Chân còn lại ấn sàn. Huyết áp cao — giữ đầu thấp. Chấn thương gân khoeo — dùng dây đai."},
  {"title": "Tư thế Khúc gỗ lửa — Agnistambhasana", "tag": "Tư thế", "url": "tu-the/tu-the-khuc-go-lua.html", "img": "assets/images/poses/agnistambhasana.webp", "time": "5 phút đọc", "content": "Tư thế Khúc gỗ lửa Agnistambhasana Mở sâu hông ngoài và cơ piriformis. Kéo giãn bẹn và đùi trong. Giảm đau thần kinh tọa. Ngồi, xếp hai ống chân chồng lên nhau (mắt cá trên đầu gối dưới). Gập nhẹ về trước để tăng độ kéo giãn. Chấn thương đầu gối — không ép gối xuống."},
  {"title": "Tư thế Xẻ dọc — Hanumanasana", "tag": "Tư thế", "url": "tu-the/tu-the-xe-doc.html", "img": "assets/images/poses/hanumanasana.webp", "time": "5 phút đọc", "content": "Tư thế Xẻ dọc Hanumanasana Kéo giãn tối đa gân khoeo, đùi trước và cơ gấp hông. Kích thích nội tạng bụng. Tăng linh hoạt toàn diện. Từ Lunge, trượt chân trước về phía trước và chân sau ra phía sau. Dùng tay hoặc khối yoga đỡ cho đến khi thoải mái. Chấn thương gân khoeo, bẹn hoặc hông — không ép, dùng khối yoga đỡ."},
  {"title": "Tư thế Cây — Vrksasana", "tag": "Tư thế", "url": "tu-the/tu-the-cay.html", "img": "assets/images/poses/vrksasana.webp", "time": "5 phút đọc", "content": "Tư thế Cây Vrksasana Cải thiện thăng bằng và sự tập trung. Tăng cường cơ chân và hông. Giúp tĩnh tâm, giảm lo âu. Đứng thẳng, nâng một chân lên đặt lòng bàn chân vào đùi hoặc bắp chân (không đặt trực tiếp lên gối). Hai tay chắp hoặc vươn lên. Đau đầu, mất ngủ, huyết áp thấp."},
  {"title": "Tư thế Đại bàng — Garudasana", "tag": "Tư thế", "url": "tu-the/tu-the-dai-bang.html", "img": "assets/images/poses/garudasana.webp", "time": "5 phút đọc", "content": "Tư thế Đại bàng Garudasana Tăng cường đùi, mắt cá và bắp chân. Kéo giãn vai và cơ rhomboid. Cải thiện tập trung và thăng bằng. Đứng, quấn chân phải qua trái, bàn chân móc vào bắp chân. Hai tay quấn vào nhau trước mặt, nâng khuỷu tay lên. Chấn thương đầu gối, mắt cá hoặc khuỷu tay."},
  {"title": "Tư thế Vũ sĩ — Natarajasana", "tag": "Tư thế", "url": "tu-the/tu-the-vu-si.html", "img": "assets/images/poses/natarajasana.webp", "time": "5 phút đọc", "content": "Tư thế Vũ sĩ Natarajasana Tăng cường thăng bằng và tập trung cao độ. Mở ngực và vai. Kéo giãn đùi trước. Nâng cao tâm trạng. Đứng một chân, gập chân sau, tay cùng bên nắm mắt cá từ bên ngoài. Nghiêng người về trước, nâng chân lên và giơ tay kia về phía trước. Huyết áp thấp, chấn thương lưng, đầu gối hoặc cổ chân."},
  {"title": "Chiến binh III — Virabhadrasana III", "tag": "Tư thế", "url": "tu-the/chien-binh-iii.html", "img": "assets/images/poses/virabhadrasana3.webp", "time": "5 phút đọc", "content": "Chiến binh III Virabhadrasana III Tăng cường cơ lưng, bụng và chân. Cải thiện thăng bằng động. Phát triển sức mạnh toàn thân. Đứng một chân, nghiêng thân trên song song sàn, chân sau nâng lên ngang hông. Hai tay duỗi sang hai bên hoặc về trước. Huyết áp cao, chấn thương hông hoặc đầu gối."},
  {"title": "Tư thế Ngón tay nâng — Utthita Hasta Padangusthasana", "tag": "Tư thế", "url": "tu-the/tu-the-ngon-tay-nang.html", "img": "assets/images/poses/utthita-hasta-padangusthasana.webp", "time": "5 phút đọc", "content": "Tư thế Ngón tay nâng Utthita Hasta Padangusthasana Tăng cường sức mạnh chân và cốt lõi, kéo giãn gân khoeo, cải thiện thăng bằng và phối hợp. Đứng một chân, nâng chân kia ra trước, tay nắm ngón chân cái (hoặc dùng dây đai). Duỗi chân thẳng dần, thân thẳng. Chấn thương mắt cá hoặc hông — giữ gối cong."},
  {"title": "Tư thế Đứng bằng tay — Adho Mukha Vrksasana", "tag": "Tư thế", "url": "tu-the/tu-the-dung-bang-tay.html", "img": "assets/images/poses/adho-mukha-vrksasana.webp", "time": "5 phút đọc", "content": "Tư thế Đứng bằng tay Adho Mukha Vrksasana Tăng cường cơ cánh tay, vai và cổ tay. Cải thiện thăng bằng và tự tin. Làm mát đầu. Đứng trước tường, tay chống sàn cách tường 15cm. Đá hai chân lên tựa tường. Giữ thắt lưng không võng. Huyết áp cao, kinh nguyệt, tổn thương cổ tay hoặc vai."},
  {"title": "Chiến binh I — Virabhadrasana I", "tag": "Tư thế", "url": "tu-the/chien-binh-i.html", "img": "assets/images/poses/virabhadrasana1.webp", "time": "5 phút đọc", "content": "Chiến binh I Virabhadrasana I Tăng cường đùi, mắt cá và lưng. Kéo giãn ngực, phổi, vai và cổ. Tăng sự tập trung và thăng bằng. Đứng dang chân rộng, chân trước quay 90°, chân sau 45°. Gập gối trước 90°. Hai tay vươn lên, hông hướng thẳng. Huyết áp cao, tim yếu. Chấn thương vai — giữ tay song song thay vì chắp."},
  {"title": "Chiến binh II — Virabhadrasana II", "tag": "Tư thế", "url": "tu-the/chien-binh-ii.html", "img": "assets/images/poses/virabhadrasana2.webp", "time": "5 phút đọc", "content": "Chiến binh II Virabhadrasana II Tăng cường và kéo giãn chân, mắt cá. Mở hông và ngực. Phát triển sức bền và sự tập trung. Đứng dang chân rộng, chân trước quay 90°. Gập gối trước 90°. Hai tay dang ngang, mắt nhìn theo tay trước. Tiêu chảy, huyết áp cao. Chấn thương đầu gối — không để gối vượt quá mắt cá."},
  {"title": "Bán nguyệt xoay — Parivrtta Ardha Chandrasana", "tag": "Tư thế", "url": "tu-the/ban-nguyet-xoay.html", "img": "assets/images/poses/parivrtta-ardha-chandrasana.webp", "time": "5 phút đọc", "content": "Bán nguyệt xoay Parivrtta Ardha Chandrasana Kết hợp thăng bằng, xoắn và mở hông. Tăng cường cốt lõi, chân và cột sống. Cải thiện phối hợp. Đứng một chân, nghiêng về trước tay đối diện chống sàn. Nâng chân sau lên, xoay thân, tay trên vươn lên trời. Huyết áp thấp, đau đầu, mất ngủ, tiêu chảy."},
  {"title": "Tư thế Tám góc — Astavakrasana", "tag": "Tư thế", "url": "tu-the/tu-the-tam-goc.html", "img": "assets/images/poses/astavakrasana.webp", "time": "5 phút đọc", "content": "Tư thế Tám góc Astavakrasana Tăng cường cổ tay, cánh tay và cốt lõi. Kết hợp thăng bằng tay với xoắn thân. Phát triển sự kiểm soát cơ thể. Ngồi, luồn một chân qua cánh tay. Hai tay chống sàn, nâng toàn thân lên. Hai chân móc vào nhau duỗi sang bên, thân nghiêng về trước. Hội chứng ống cổ tay, chấn thương vai hoặc cổ tay. Thai kỳ."},
  {"title": "Tư thế Chân lên tường — Viparita Karani", "tag": "Tư thế", "url": "tu-the/tu-the-chan-len-tuong.html", "img": "assets/images/poses/viparita-karani.webp", "time": "5 phút đọc", "content": "Tư thế Chân lên tường Viparita Karani Giảm mệt mỏi chân và phù nề, cải thiện tuần hoàn tĩnh mạch, thư giãn hệ thần kinh, giảm lo âu nhẹ nhàng. Nằm gần tường, đưa chân lên tựa tường thẳng hoặc hơi cong. Hai tay đặt xuôi thân. Thở đều và thư giãn. Tăng nhãn áp, viêm khớp nặng ở cổ, kinh nguyệt nhiều."},
  {"title": "Đứng bằng vai — Salamba Sarvangasana", "tag": "Tư thế", "url": "tu-the/dung-bang-vai.html", "img": "assets/images/poses/salamba-sarvangasana.webp", "time": "5 phút đọc", "content": "Đứng bằng vai Salamba Sarvangasana Tăng tuần hoàn máu lên não, kích thích tuyến giáp và tuyến cận giáp, giảm cảm giác lo âu và mệt mỏi. Nằm ngửa, nâng chân rồi hông lên, tay đỡ lưng. Toàn thân thẳng từ bờ vai đến gót chân, cổ không nên ép. Kinh nguyệt, thai kỳ, cao huyết áp, chấn thương cổ, tăng nhãn áp."},
  {"title": "Tư thế Cày — Halasana", "tag": "Tư thế", "url": "tu-the/tu-the-cay-halasana.html", "img": "assets/images/poses/halasana.webp", "time": "5 phút đọc", "content": "Tư thế Cày Halasana Kéo giãn cột sống và vai. Kích thích tuyến giáp. Giảm stress và mệt mỏi. Cải thiện tiêu hóa. Từ đứng bằng vai, hạ chân qua đầu xuống sàn phía sau. Tay có thể đỡ lưng hoặc duỗi thẳng trên sàn. Kinh nguyệt, thai kỳ, cao huyết áp, chấn thương cổ, tiêu chảy, hen suyễn."},
  {"title": "Chó úp mặt — Adho Mukha Svanasana", "tag": "Tư thế", "url": "tu-the/cho-up-mat.html", "img": "assets/images/poses/adho-mukha-svanasana.webp", "time": "5 phút đọc", "content": "Chó úp mặt Adho Mukha Svanasana Đảo ngược nhẹ nhàng, tăng lưu thông máu lên não. Kéo giãn cột sống. Phù hợp người mới bắt đầu đảo ngược. Tứ chi chống sàn, nâng hông lên tạo chữ V ngược. Đầu thả lỏng dưới tim — đây là dạng đảo ngược nhẹ. Huyết áp rất cao, hội chứng ống cổ tay, 3 tháng cuối thai kỳ."},
  {"title": "Đứng bằng đầu — Salamba Sirsasana", "tag": "Tư thế", "url": "tu-the/dung-bang-dau.html", "img": "assets/images/poses/salamba-sirsasana.webp", "time": "5 phút đọc", "content": "Đứng bằng đầu Salamba Sirsasana Tăng cường lưu thông máu lên não, tăng sức mạnh vai và cốt lõi, cải thiện hệ tiêu hóa và bạch huyết. Quỳ, đan các ngón tay làm nền, đặt đỉnh đầu xuống sàn. Nâng hông lên và từ từ nâng hai chân. Cần thực hành có hướng dẫn. Cao huyết áp, tăng nhãn áp, kinh nguyệt, thai kỳ, chấn thương cổ — chỉ tập với huấn luyện viên."},
  {"title": "Tư thế Bọ cạp — Vrischikasana", "tag": "Tư thế", "url": "tu-the/tu-the-bo-cap.html", "img": "assets/images/poses/vrischikasana.webp", "time": "5 phút đọc", "content": "Tư thế Bọ cạp Vrischikasana Tăng cường sức mạnh vai và cốt lõi mạnh mẽ. Mở ngực sâu. Cải thiện thăng bằng tuyệt đối. Từ tư thế cẳng tay Pincha Mayurasana, uốn cong lưng, hạ ngực và uốn đôi chân qua đầu như đuôi bọ cạp. Chấn thương lưng, vai, cổ, huyết áp cao."},
  {"title": "Đứng bằng cẳng tay — Pincha Mayurasana", "tag": "Tư thế", "url": "tu-the/dung-bang-cang-tay.html", "img": "assets/images/poses/pincha-mayurasana.webp", "time": "5 phút đọc", "content": "Đứng bằng cẳng tay Pincha Mayurasana Tăng cường vai, cánh tay và cốt lõi. Cải thiện thăng bằng. Kéo giãn cột sống và ngực. Quỳ, đặt cẳng tay và bàn tay xuống sàn. Nâng hông lên, đá chân lên (tựa tường nếu cần). Giữ thẳng từ khuỷu đến gót. Chấn thương vai, lưng hoặc cổ. Huyết áp cao. Thai kỳ."},
  {"title": "Tư thế Cá heo — Ardha Sirsasana", "tag": "Tư thế", "url": "tu-the/tu-the-ca-heo.html", "img": "assets/images/poses/dolphin-pose.webp", "time": "5 phút đọc", "content": "Tư thế Cá heo Ardha Sirsasana Tăng cường vai, cánh tay và cốt lõi. Chuẩn bị cho Đứng bằng đầu và Đứng bằng cẳng tay. Kéo giãn gân khoeo. Như Chó úp mặt nhưng trên cẳng tay. Đan ngón tay, đỉnh đầu giữa hai tay. Đẩy hông lên cao, thẳng cột sống. Chấn thương vai hoặc cổ. Huyết áp cao."},
  {"title": "Tư thế Ép tai — Karnapidasana", "tag": "Tư thế", "url": "tu-the/tu-the-ep-tai.html", "img": "assets/images/poses/karnapidasana.webp", "time": "5 phút đọc", "content": "Tư thế Ép tai Karnapidasana Kéo giãn sâu cột sống và vai. Kích thích tuyến giáp. Giảm stress và mệt mỏi. Làm dịu tinh thần. Từ tư thế Cày (Halasana), gập gối hạ xuống cạnh tai. Tay đặt trên lưng hoặc duỗi thẳng trên sàn. Chấn thương cổ, huyết áp cao, kinh nguyệt, tiêu chảy, hen suyễn."},
  {"title": "Cầu phục hồi — Setu Bandha Supported", "tag": "Tư thế", "url": "tu-the/cau-phuc-hoi.html", "img": "assets/images/poses/setu-bandha-restorative.webp", "time": "5 phút đọc", "content": "Cầu phục hồi Setu Bandha Supported Đảo ngược nhẹ nhàng, mở ngực, giảm mệt mỏi. Kích thích tuyến giáp. Phù hợp phục hồi sau buổi tập. Nằm ngửa, gập gối, nâng hông lên. Đặt khối yoga dưới xương cùng. Thả lỏng tay hai bên, thở sâu. Chấn thương cổ — giữ cổ không xoay."},
  {"title": "Tư thế Xác chết — Savasana", "tag": "Tư thế", "url": "tu-the/tu-the-xac-chet.html", "img": "assets/images/poses/savasana.webp", "time": "5 phút đọc", "content": "Tư thế Xác chết Savasana Thư giãn toàn thân sâu nhất. Hợp nhất lợi ích của toàn buổi tập. Phục hồi hệ thần kinh. Giảm huyết áp. Nằm ngửa, tay chân buông lơi tự nhiên, lòng bàn tay ngửa. Nhắm mắt, thở bình thường. Giữ ít nhất 5–10 phút. Không có chống chỉ định — điều chỉnh bằng gối đệm nếu cần."},
  {"title": "Nằm ngửa bướm — Supta Baddha Konasana", "tag": "Tư thế", "url": "tu-the/nam-ngua-buom.html", "img": "assets/images/poses/supta-baddha-konasana.webp", "time": "5 phút đọc", "content": "Nằm ngửa bướm Supta Baddha Konasana Mở nhẹ hông và bẹn khi nằm ngửa. Thư giãn hoàn toàn. Tốt cho người căng thẳng, mất ngủ và mang thai. Nằm ngửa, hai lòng bàn chân áp vào nhau, đầu gối mở sang hai bên. Tay đặt bụng hoặc xuôi thân. Thở sâu, thư giãn sâu. Chấn thương bẹn hoặc đầu gối — kê gối đệm dưới đùi."},
  {"title": "Ngồi thiền tĩnh — Sukhasana (Thiền)", "tag": "Tư thế", "url": "tu-the/ngoi-thien-tinh.html", "img": "assets/images/poses/sukhasana.webp", "time": "5 phút đọc", "content": "Ngồi thiền tĩnh Sukhasana (Thiền) Kết thúc buổi tập với tâm trí tĩnh lặng. Ổn định hệ thần kinh tự chủ. Tăng sự hiện diện và nhận thức. Ngồi xếp bằng thoải mái, cột sống thẳng. Nhắm mắt, tập trung vào hơi thở tự nhiên. Giữ 3–10 phút. Không có chống chỉ định — dùng gối nếu hông cứng."},
  {"title": "Cá phục hồi — Matsyasana Restorative", "tag": "Tư thế", "url": "tu-the/ca-phuc-hoi.html", "img": "assets/images/poses/matsyasana-restorative.webp", "time": "5 phút đọc", "content": "Cá phục hồi Matsyasana Restorative Mở ngực và cổ họng sâu khi được hỗ trợ. Giảm lo âu và căng thẳng. Kéo giãn nhẹ nhàng cơ gian sườn. Đặt gối bolster dọc cột sống, nằm ngửa lên. Hai tay giang rộng, lòng bàn tay ngửa. Thở sâu, thả lỏng hoàn toàn. Chấn thương cổ — dùng chăn đỡ đầu."},
  {"title": "Chân lên tường phục hồi — Viparita Karani (Phục hồi)", "tag": "Tư thế", "url": "tu-the/chan-len-tuong-phuc-hoi.html", "img": "assets/images/poses/viparita-karani-rest.webp", "time": "5 phút đọc", "content": "Chân lên tường phục hồi Viparita Karani (Phục hồi) Giảm phù nề chân, cải thiện tuần hoàn. Thư giãn toàn bộ hệ thần kinh. Hỗ trợ giấc ngủ. Nằm sát tường, nâng chân lên tựa tường. Đặt gối dưới hông nếu muốn. Tay thả lỏng, mắt nhắm. Giữ 5–15 phút. Tăng nhãn áp, kinh nguyệt nặng."},
  {"title": "Tư thế Cá sấu — Makarasana", "tag": "Tư thế", "url": "tu-the/tu-the-ca-sau.html", "img": "assets/images/poses/makarasana.webp", "time": "5 phút đọc", "content": "Tư thế Cá sấu Makarasana Thư giãn lưng dưới và vai. Cải thiện nhịp thở bụng. Giảm căng thẳng và mệt mỏi. Phù hợp nghỉ giữa buổi tập. Nằm sấp, gập hai tay chồng lên nhau, đặt trán lên cẳng tay. Chân mở nhẹ, ngón chân quay ra ngoài. Thở bụng sâu. Không có chống chỉ định — điều chỉnh vị trí tay nếu đau cổ."},
  {"title": "Yoga Nidra — Yoga Nidra", "tag": "Tư thế", "url": "tu-the/yoga-nidra.html", "img": "assets/images/poses/yoga-nidra.webp", "time": "5 phút đọc", "content": "Yoga Nidra Yoga Nidra Phục hồi sâu nhất — 30 phút Yoga Nidra tương đương 2 giờ ngủ. Giảm stress mãn tính. Cải thiện chất lượng giấc ngủ. Nằm Savasana với gối dưới đầu gối, chăn đắp ấm, mắt bịt nhẹ. Nghe hướng dẫn quét cơ thể. Giữ tỉnh táo nhưng thư giãn. Không có chống chỉ định."},
  {"title": "Trẻ em phục hồi — Balasana (Restorative)", "tag": "Tư thế", "url": "tu-the/tre-em-phuc-hoi.html", "img": "assets/images/poses/balasana-restorative.webp", "time": "5 phút đọc", "content": "Trẻ em phục hồi Balasana (Restorative) Thư giãn sâu toàn thân khi được hỗ trợ bởi gối bolster. Giải phóng lưng dưới, hông và vai. An toàn cho mọi cấp độ. Quỳ gối mở rộng, đặt gối bolster giữa hai đùi. Cúi người ôm lên bolster, má tựa nhẹ. Thở sâu, giữ 3–5 phút. Chấn thương đầu gối nặng — kê thêm chăn giữa mông và gót."}
